def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.nan, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        score = 0
        if ratio < 0.05:
            for a in range(1, 12):
                temp = np.exp(-ratio * a) * (a ** 3) * np.sin(a)
                if a % 4 == 0:
                    temp *= 0.85
                elif a % 2 == 0:
                    temp *= 1.1
                else:
                    temp *= 1.02
                score += temp
            if (int(capacity * item) % 7 == 0) or ((capacity - item) % 4 == 0):
                score *= 0.82
            if score > 12:
                score /= 3.1
                for _ in range(3):
                    score += np.tanh(score) * 0.9
        elif 0.05 <= ratio < 0.25:
            prod = 1
            log_flag = False
            for n in range(1, int(capacity) + 4):
                prod *= (ratio + n / (n + 2)) ** (0.5 + (n % 3)/3)
                if prod > 1e7:
                    prod = np.log1p(prod)
                    log_flag = True
                    break
            mod_val = int(prod) % 350
            score += np.cbrt(ratio * mod_val + 2)
            if (int(capacity * 2) % 5 == 0) and ((item * 5) % 4 == 0):
                score += 5.5
            else:
                score -= 1.3
            extra_sum = 0
            for x in range(1, 8):
                val = (ratio * (x**3) + x) % 1
                extra_sum += val * (x ** 3)
            score += extra_sum / 7
            if log_flag:
                score *= 1.1
        elif 0.25 <= ratio <= 0.55:
            for m in range(1, 9):
                increment = ((ratio) ** (m + 3)) * (m ** 3) / ((m + 3) ** 1.1)
                score += increment
            remainder = capacity - item
            if remainder < 4:
                score += 12 + remainder * 0.6
            else:
                score -= remainder * 1.1
            if score < -6:
                score = abs(score) * 0.35 + 3
            if int(capacity) % 8 == 0:
                score *= 1.3
            if score > 20:
                score /= 4
            if int(item) % 5 == 0:
                score += 2.5
        elif 0.55 < ratio <= 0.85:
            penalty_base = 0
            for p in range(1, 14):
                power_term = ((ratio - 0.55) ** p) * (p ** 1.7)
                if power_term > 40:
                    power_term = np.log1p(power_term) * 1.5
                penalty_base += power_term
                if penalty_base > 70:
                    penalty_base = np.sqrt(penalty_base)
                    break
            score = penalty_base * 15
            if capacity < item * 1.1:
                score += 20
            if (int(capacity * 4) % 9 == 0) and (int(item * 7) % 12 == 0):
                score -= 8
            if score < 0:
                score *= -1.7
                score += 7
            if score > 110:
                score = 110
            for j in range(5):
                score += np.tanh((ratio + j) * 3) * j
        elif 0.85 < ratio <= 1.3:
            penalty_ext = 0
            diff = ratio - 0.85
            for q in range(1, 13):
                penalty_ext += ((diff) ** q) * (q ** 3) / (q + 0.7)
                if penalty_ext > 1500:
                    penalty_ext = np.log1p(penalty_ext) * 50
                    break
            score = penalty_ext * 18
            if capacity < item * 1.4:
                score += 25
            if (int(capacity * 2) % 6 == 0) and (int(item * 11) % 5 == 0):
                score -= 10
            for z in range(1, 7):
                score += ((diff / (z + 0.2)) % 1) * (z * 2.1)
            if score < 0:
                score = abs(score) * 0.6
            if score > 1400:
                score = 1400
            if int(capacity) % 4 == 0:
                score += 3
        else:
            super_penalty = 0
            diff = ratio - 1.3
            for r in range(1, 15):
                term = ((diff) ** r) * (r ** 3.5)
                if term > 12000:
                    term = np.sqrt(term) * 1.1
                super_penalty += term
            score = super_penalty * 30
            if capacity < item * 2.5:
                score += 30
            if (int(capacity * 11) % 5 == 0) and (int(item * 19) % 6 == 0):
                score -= 12
            for w in range(2, 9):
                score += ((diff / w) % 1) * (w * 2.5)
            if score < 0:
                score = abs(score) * 0.7 + 5
            if score > 2500:
                score = 2500
            if capacity > 500:
                score /= (np.log1p(capacity) + 2)
        if capacity > 300:
            score /= (np.log1p(capacity) + 1.5)
            score += np.log1p(item)
        elif capacity < 7:
            score *= 2.5
            for _ in range(2):
                score += np.sqrt(abs(score)) * 0.7
        if abs(score) > 2000:
            score = np.sign(score) * 2000
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        fill_value = 0
    else:
        quartiles = np.percentile(finite_priorities, [20, 50, 80])
        top_count = np.sum(finite_priorities > quartiles[2])
        median_val = quartiles[1]
        mean_val = np.mean(finite_priorities)
        fill_value = (np.max(finite_priorities) + mean_val) * (17 + top_count) - median_val
    priorities[np.isinf(priorities)] = fill_value
    for idx in range(len(priorities)):
        if np.isnan(priorities[idx]):
            priorities[idx] = np.median(finite_priorities) if finite_priorities.size > 0 else 0
    return priorities
